import type {
  ComboboxCompactEmits,
  ComboboxCompactProps,
  ComboboxCompactSlots,
  ComboboxUi
} from '@soybeanjs/headless/combobox';
import type { ClassValue } from '@soybeanjs/headless/types';
import type { ThemeSize } from '@/theme';

/**
 * Properties for the Combobox component.
 */
export interface ComboboxProps<M extends boolean = false> extends ComboboxCompactProps<M> {
  /**
   * Additional class names applied to the root element.
   */
  class?: ClassValue;
  /**
   * Visual size of the component.
   */
  size?: ThemeSize;
  /**
   * Per-slot class overrides for the component.
   */
  ui?: Partial<ComboboxUi>;
}

/**
 * Events for the Combobox component.
 */
export type ComboboxEmits<M extends boolean = false> = ComboboxCompactEmits<M>;

/**
 * Slots for the Combobox component.
 */
export type ComboboxSlots<M extends boolean = false> = ComboboxCompactSlots<M>;

export { default as SCombobox } from './combobox.vue';

export type * from '@soybeanjs/headless/combobox';
export type * from './types';

import type { ThemeSize } from './types';

export const themeSizeMap: Record<ThemeSize, number> = {
  xs: 12,
  sm: 14,
  md: 16,
  lg: 18,
  xl: 20,
  '2xl': 24
};
export const miniSizeMap: Record<ThemeSize, ThemeSize> = {
  xs: 'xs',
  sm: 'xs',
  md: 'sm',
  lg: 'md',
  xl: 'lg',
  '2xl': 'xl'
};

export const themeSizeRatio = Object.fromEntries(
  Object.entries(themeSizeMap).map(([key, value]) => [key, value / themeSizeMap.md])
) as Record<ThemeSize, number>;
